Can this be a helper method?

```python
try:
    return self._construct_and_send_jwt_auth(sub, sub_type)
except BoxOAuthException as ex:
    box_datetime = self._get_date_header(ex.network_response)
    if (box_datetime is not None) and self._exp_claim_rejected_due_to_clock_skew(ex.network_response):
        return self._construct_and_send_jwt_auth(sub, sub_type, box_datetime)
    raise

@staticmethod
def _get_date_header(network_response):
    """Get datetime object for Date header, if it is available.

    Returns None if Date header is absent or can't be parsed.
    """
    if 'Date' not in network_response.headers:
        return None
    box_date_header = network_response.headers['Date']
    try:
        return datetime.strptime(box_date_header, '%a, %d %b %Y %H:%M:%S %Z')
    except ValueError:
        return None

@staticmethod
def _exp_claim_rejected_due_to_clock_skew(network_response):
    status_code = error_response.status_code
    try:
        json_response = error_response.json()
    except ValueError:
        return False
    error_code = json_response.get('error', '')
    error_description = json_response.get('error_description', '')
    return (status_code == 400) and (error_code == 'invalid_grant') and ('exp' in error_description)
```

Should be the exact same instance. The calling sequence are the following:
```python
# Trainer.__init__ calls Trainer._init_optimizer:
    def _init_optimizer(self, optimizer, optimizer_params):
        param_dict = {i: param for i, param in enumerate(self._params)}
        if isinstance(optimizer, opt.Optimizer):
            assert not optimizer_params, \
                "optimizer_params must be None if optimizer is an instance of " \
                "Optimizer instead of str"
            self._optimizer = optimizer
            self._optimizer.param_dict = param_dict
        else:
            self._optimizer = opt.create(optimizer, param_dict=param_dict,
                                         **optimizer_params)

        self._updaters = [opt.get_updater(self._optimizer) \
                            for _ in self._contexts]

# and optimizer.get_updater is:
def get_updater(optimizer):
    return Updater(optimizer)

# and Updater __init__ looks like this:
class Updater(object):
    """Updater for kvstore."""
    def __init__(self, optimizer):
        self.optimizer = optimizer
```

It looks like this is more or less the same as the previous component except for templateUrl. It looks like you can make templateUrl "injectable" by making it a function as opposed to a string: http://stackoverflow.com/a/33846452 So maybe we could just parametrize this part of phCompareTable above and save the duplication? Maybe something like this:

```js
templateUrl: function($element, $attrs) {
   if ($attrs.type === 'trend')
      return 'partials/perf/trendtable.html';
   return 'partials/perf/comparetable.html'
},
```

